import 'package:flutter/material.dart';
import 'package:paytm_sdk/paytm_sdk.dart';
import 'package:google_pay_sdk/google_pay_sdk.dart';

class PaymentModule extends StatefulWidget {
  @override
  _PaymentModuleState createState() => _PaymentModuleState();
}

class _PaymentModuleState extends State<PaymentModule> {
  final List<String> paymentMethods = [
    'paytm',
    'google_pay'
  ];

  void _handlePaymentMethodChange(paymentMethod) async {
    if (paymentMethod == 'paytm') {
      // Use Paytm SDK for payment processing
      final paytmSdk = PaytmSdk();
      await paytmSdk.initialize();

      // Request for payment authorization
      final paymentResponse = await paytmSdk.requestPayment({
        'amount': 100,
        'currency': 'INR',
        'orderId': DateTime.now().millisecondsSinceEpoch.toString(),
        'callbackUrl': 'https://example.com/payments/callback',
      });

      // Handle payment response
      if (paymentResponse != null) {
        if (paymentResponse.status == PaytmSdkStatus.success) {
          print('Payment successful');
        } else {
          print('Payment failed with error: ${paymentResponse.error}');
        }
      }
    } else if (paymentMethod == 'google_pay') {
      // Use Google Pay SDK for payment processing
      final googlePaySdk = GooglePaySdk();

      // Request for payment authorization
      final paymentResponse = await googlePaySdk.requestPayment({
        'amount': 100,
        'currency': 'INR',
        'orderId': DateTime.now().millisecondsSinceEpoch.toString(),
        'callbackUrl': 'https://example.com/payments/callback',
      });

      // Handle payment response
      if (paymentResponse != null) {
        if (paymentResponse.status == GooglePaySdkStatus.success) {
          print('Payment successful');
        } else {
          print('Payment failed with error: ${paymentResponse.error}');
        }
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: <Widget>[
            DropdownButton<String>(
              value: paymentMethods[0],
              items: paymentMethods.map((method) {
                return DropdownMenuItem<String>(
                  value: method,
                  child: Text(method),
                );
              }).toList(),
              onChanged: _handlePaymentMethodChange,
            ),
            ElevatedButton(
              onPressed: () => _handlePaymentMethodChange(paymentMethods[0]),
              child: Text('Pay'),
            ),
          ],
        ),
      ),
    );
  }
}